UPDATE payment_intents
SET status = 'PENDING_AUTH',
updated_at = #{now}
WHERE payment_intent_id = #{id}
AND status = 'CREATED'

UPDATE payment_intents
SET psp_reference = #{pspReference},
updated_at = #{now, typeHandler=com.dogancaglar.common.db.typehandler.InstantTypeHandler}
WHERE payment_intent_id = #{paymentIntentId}
